/**
 * Look up ASHRAE design conditions by US zip code.
 * Returns partial DesignConditions that can be spread over defaults.
 */
export function lookupByZip(zip: string): {
  found: boolean;
  city?: string;
  state?: string;
  conditions?: Partial<DesignConditions>;
} {
  const prefix = zip.replace(/\D/g, '').slice(0, 3);
  const entry = DATA[prefix];
  if (!entry) return { found: false };

  return {
    found: true,
    city: entry.city,
    state: entry.state,
    conditions: {
      outdoorHeatingTemp: entry.heat99,
      outdoorCoolingTemp: entry.cool1,
      latitude: entry.lat,
      elevation: entry.elev,
      coolingDailyRange: entry.range,
      outdoorGrains: entry.grains,
    },
  };
}

/** Get all available zip prefixes (for autocomplete) */
export function getAvailablePrefixes(): string[] {
  return Object.keys(DATA).sort();
}

/** Quick display label for a zip prefix */
export function getLocationLabel(zip: string): string | null {
  const prefix = zip.replace(/\D/g, '').slice(0, 3);
  const entry = DATA[prefix];
  if (!entry) return null;
  return `${entry.city}, ${entry.state}`;
}
